import '../lib/redirect_follower.dart';
import '../lib/redirect_request.dart';
import '../lib/redirect_response.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

bool hasHeader(Map<String, String> headers, String name) {
  final normalized = name.toLowerCase();
  return headers.keys.any((key) => key.toLowerCase() == normalized);
}

void main() {
  final follower = RedirectFollower();
  final completed = follower.follow(
    RedirectRequest(
      method: 'PATCH',
      uri: Uri.parse('https://api.example.test:443/v1/uploads/item-9'),
      headers: const <String, String>{
        'AUTHORIZATION': 'Bearer upload-token',
        'cOoKiE': 'session=private',
        'Proxy-Authorization': 'Basic cHJveHk=',
        'Content-Type': 'application/octet-stream',
        'Transfer-Encoding': 'chunked',
        'X-Trace': 'trace-9',
      },
      body: const <int>[9, 8, 7, 6],
    ),
    <RedirectResponse>[
      RedirectResponse(
        statusCode: 303,
        location: 'https://objects.example.test/staging/item-9',
      ),
      RedirectResponse(
        statusCode: 308,
        location: '../complete/item-9?version=2',
      ),
    ],
  );

  check(
    completed.uri.toString() ==
        'https://objects.example.test/complete/item-9?version=2',
    'each location resolves from the request that received it',
  );
  check(completed.method == 'GET', 'derived method survives a later redirect');
  check(completed.body == null, 'a consumed entity is not restored later');
  check(
    !hasHeader(completed.headers, 'content-type') &&
        !hasHeader(completed.headers, 'transfer-encoding'),
    'mixed entity metadata remains absent across the chain',
  );
  check(
    !hasHeader(completed.headers, 'authorization') &&
        !hasHeader(completed.headers, 'cookie') &&
        !hasHeader(completed.headers, 'proxy-authorization'),
    'case-insensitive credentials remain outside the new authority',
  );
  check(
    completed.headers['X-Trace'] == 'trace-9',
    'ordinary metadata survives a multi-hop handoff',
  );

  final equivalentOrigin = follower.follow(
    RedirectRequest(
      method: 'GET',
      uri: Uri.parse('https://api.example.test/start'),
      headers: const <String, String>{'Authorization': 'Bearer reader'},
    ),
    <RedirectResponse>[
      RedirectResponse(
        statusCode: 308,
        location: 'https://api.example.test:443/next',
      ),
    ],
  );
  check(
    equivalentOrigin.headers['Authorization'] == 'Bearer reader',
    'an explicit default port is the same origin',
  );

  final head = RedirectPolicy().derive(
    RedirectRequest(
      method: 'HEAD',
      uri: Uri.parse('https://api.example.test/check'),
      headers: const <String, String>{'Accept': 'application/json'},
    ),
    statusCode: 303,
    target: Uri.parse('https://api.example.test/result'),
  );
  check(head.method == 'HEAD', 'see-other preserves HEAD semantics');
  check(
    head.headers['Accept'] == 'application/json',
    'read metadata remains intact',
  );

  print('final tests passed');
}
